pragma solidity ^0.8.9;

import "./ContractGlossaryStorage.sol";

contract ContractGlossaryReadableFacet {

    function getAddressFromContractGlossary(
        string memory contractName
    )
    public
    view
    returns (
        address contractAddress
    ){
        ContractGlossaryStorage.Layout storage lcg = ContractGlossaryStorage.layout();
        contractAddress = lcg.nameToAddress[contractName];
    }

    function getNameFromContractGlossary(
        address contractAddress
    )
    public
    view
    returns (
        string memory contractName
    ){
        ContractGlossaryStorage.Layout storage lcg = ContractGlossaryStorage.layout();
        contractName = lcg.addressToName[contractAddress];
    }

    function getContractGlossaryEntries()
    public
    view
    returns (
        GlossaryReference[] memory
    ){
        ContractGlossaryStorage.Layout storage lcg = ContractGlossaryStorage.layout();
        GlossaryReference[] memory glossaryEntries = new GlossaryReference[](lcg.glossarySize);
        uint256 i;
        for(; i < lcg.glossarySize;){
            glossaryEntries[i] = GlossaryReference(
                i,
                lcg.indexToName[i],
                lcg.nameToAddress[lcg.indexToName[i]],
                true
            );
            unchecked { i++; }
        }
        return glossaryEntries;
    }
}","keccak256":"0x9dbf04c1aaa5bbcc4e816ebbe7c1ac166455d19169932209f33ba113b06463f7","license":"UNLICENSED"},"contracts/facets/glossary/ContractGlossaryStorage.sol":{"content":"// SPDX-License-Identifier: UNLICENSED
pragma solidity ^0.8.9;

import { EnumerableSet } from "@solidstate/contracts/data/EnumerableSet.sol";

    struct GlossaryReference {
        uint256 glossaryId;
        string contractName;
        address contractAddress;
        bool valid;
    }

library ContractGlossaryStorage {

    bytes32 internal constant STORAGE_SLOT = keccak256('silks.contracts.storage.SilksContractGlossary');

    struct Layout {
        mapping(uint256 => string) indexToName;
        mapping(string => address) nameToAddress;
        mapping(address => string) addressToName;
        uint256 glossarySize;
    }

    // Function to retrieve the layout.
    function layout()
    internal
    pure
    returns (
        Layout storage _l
    ) {
        bytes32 slot = STORAGE_SLOT;
        assembly {
            _l.slot := slot
        }
    }

    function addContractGlossaryEntry(
        string memory name,
        address contractAddress
    )
    internal
    {
        if (layout().nameToAddress[name] == address(0)) {
            layout().indexToName[layout().glossarySize] = name;
            layout().glossarySize++;
        }
        layout().nameToAddress[name] = contractAddress;
        layout().addressToName[contractAddress] = name;
    }
}","keccak256":"0x7f672bf6950cddbe93aaf51149d888c5eafa021cca1dfcc20e3ed86ff6b5201b","license":"UNLICENSED"}},"version":1}
